mapper.delete:
/* ESS충방전량 삭제 */
DELETE FROM tb_ess_charge 
 WHERE ess_chg_idx = #{essChgIdx}

mapper.select:
/* ESS충방전량 전체 개수 조회 */
SELECT COUNT(*) AS CNT
  FROM tb_ess_charge
 WHERE ess_chg_idx = #{essChgIdx}

/* ESS충방전량 목록 조회 BySiteId */
SELECT site_id,
       std_date,
       SUM(chg_val) chg_val,
       SUM(dischg_val) dischg_val
  FROM tb_ess_charge
 WHERE site_id = #{siteId}
   AND std_date BETWEEN #{beginDate} AND #{endDate}
 GROUP BY site_id, std_date
